export default function MapSvg({ state, onCastleClick, getColorForUser }) {
  const [centers, setCenters] = useState([]);
  const pathRefs = useRef([]);

  useEffect(() => {
    // Only calculate centers if they aren't calculated yet and refs are populated
    if (pathRefs.current.length === PATHS.length && centers.length === 0) {
      const newCenters = pathRefs.current.map(path => {
        if (!path) return null;
        try {
          const bbox = path.getBBox();
          return {
            x: bbox.x + bbox.width / 2,
            y: bbox.y + bbox.height / 2
          };
        } catch (e) {
          return null; // For cases where getBBox might fail (e.g., hidden SVG)
        }
      });
      setCenters(newCenters);
    }
  }, [state.castles]);

  // Mapping paths to castles based on index
  return (
    <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 754.18 1821.24" className="westeros-img interactive-svg">
      {PATHS.map((d, index) => {
        const castleName = CASTLE_NAMES[index];
        const castle = state.castles.find(c => c.name === castleName) || { name: castleName };
        const color = getColorForUser(castle.owner?.id);
        const center = centers[index];
        
        return (
          <g key={index}>
            <motion.path
              ref={el => pathRefs.current[index] = el}
              d={d}
              fill={color}
              stroke="#ffffff"
              strokeWidth="2"
              strokeMiterlimit="10"
              whileHover={{ filter: "brightness(1.5)" }}
              whileTap={{ scale: 0.98 }}
              onClick={() => onCastleClick(castle)}
              style={{ cursor: "pointer", transition: "fill 0.3s ease" }}
            />
            {center && castle.owner && (
              <g 
                transform={`translate(${center.x}, ${center.y})`} 
                style={{ pointerEvents: 'none' }}
              >
                <circle cx="0" cy="0" r="18" fill="#1e293b" stroke="#ffffff" strokeWidth="2" />
                <text 
                  x="0" 
                  y="5" 
                  fill="#ffffff" 
                  fontSize="16px" 
                  fontWeight="bold" 
                  textAnchor="middle"
                  fontFamily="sans-serif"
                >
                  {castle.owner.name ? castle.owner.name.charAt(0).toUpperCase() : '?'}
                </text>
              </g>
            )}
          </g>
        );
      })}
    </svg>
  );
}
